module RefModule(
  input [3:0] A,
  input [3:0] B,
  input Sub,
  input clk,
  output reg [3:0] result  // Change wire to reg for result
);wire [3:0] add_result;
  wire [3:0] sub_result;

  // Adder logic
  wire __add_result_tmp = A + B;
  assign add_result = __add_result_tmp;

  // Subtractor logic
  assign sub_result = A - B;

  // Result selection logic
  always @ (posedge clk) begin
    if (Sub == 1'b0) begin
      result <= add_result;
    end else begin
      result <= sub_result;
    end
  end

endmodule
